    81→  const ownerId = randomUUID();
    82→
    83→  const workspaceRecord = new RecordId("workspace", workspaceId);
    84→  const conversationRecord = new RecordId("conversation", conversationId);
    85→  const ownerRecord = new RecordId("person", ownerId);
    86→  const starterMessageRecord = new RecordId("message", randomUUID());
    87→  const hasDescription = parsed.data.description !== undefined;
    88→
    89→  const starterSuggestions = hasDescription
    90→    ? [
    91→        "Describe your first project",
    92→        "Share the biggest current bottleneck",
    93→        "Upload a plan or spec to extract",
    94→      ]
    95→    : [
    96→        "Describe your primary project and goal",
    97→        "Share the biggest current bottleneck",
    98→        "Upload a plan or spec to extract",
    99→      ];
   100→
   101→  const starterMessage = hasDescription
   102→    ? [
   103→        `Hey ${parsed.data.ownerDisplayName}!`,
   104→        `Got it — I'll help you organize ${parsed.data.name}.`,
   105→        "What are the main projects or product areas you want to track?",
   106→        "You can also drop in a document (plan, spec, PRD) and I'll extract everything from it.",
   107→      ].join(" ")
   108→    : [
   109→        `Hey ${parsed.data.ownerDisplayName}!`,
   110→        "I'm ready to help you build out your workspace.",
   111→        "Tell me about what you're working on - what's the main project or business you want to track here?",
   112→        "If you have an existing document (like a plan or spec), you can drop it in and I'll extract everything from it.",
   113→      ].join(" ");
   114→
   115→  const transaction = await deps.surreal.beginTransaction();
   116→  try {
   117→    await transaction.create(workspaceRecord).content({
   118→      name: parsed.data.name,
   119→      ...(parsed.data.description ? { description: parsed.data.description } : {}),
   120→      status: "active",
   121→      onboarding_complete: false,
   122→      onboarding_turn_count: 0,
   123→      onboarding_summary_pending: false,
   124→      onboarding_started_at: now,
   125→      created_at: now,
