   135→      name: parsed.data.ownerDisplayName,
   136→      ...(ownerEmbedding ? { embedding: ownerEmbedding } : {}),
   137→      created_at: now,
   138→      updated_at: now,
   139→    });
   140→
   141→    await transaction.relate(ownerRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
   142→      role: "owner",
   143→      added_at: now,
   144→    }).output("after");
   145→
   146→    await transaction.create(conversationRecord).content({
   147→      createdAt: now,
   148→      updatedAt: now,
   149→      workspace: workspaceRecord,
   150→      source: "onboarding",
   151→      title: "Onboarding",
   152→      title_source: "message",
   153→    });
   154→
   155→    await transaction.create(starterMessageRecord).content({
   156→      conversation: conversationRecord,
