   190→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
   191→  const startedAt = performance.now();
   192→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
   193→
   194→  try {
   195→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
   196→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
   197→    if (!workspace) {
   198→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
   199→    }
   200→
   201→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
   202→    const conversationId = conversationRecord.id as string;
   203→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
   204→
   205→    const messages = rawMessages.map((row) => ({
   206→      id: row.id,
   207→      role: row.role,
   208→      text: row.text,
   209→      createdAt: toIsoString(row.createdAt),
   210→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
   211→      ...(row.inherited ? { inherited: true } : {}),
   212→    } satisfies WorkspaceBootstrapMessage));
   213→
   214→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
   215→    const onboardingState = toOnboardingState(workspace);
   216→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
   217→
   218→    const payload: WorkspaceBootstrapResponse = {
   219→      workspaceId: workspace.id.id as string,
   220→      workspaceName: workspace.name,
   221→      ...(workspace.description ? { workspaceDescription: workspace.description } : {}),
   222→      onboardingComplete: workspace.onboarding_complete,
   223→      onboardingState,
   224→      conversationId: conversationRecord.id as string,
   225→      messages,
   226→      seeds,
   227→      sidebar,
   228→    };
   229→
   230→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
   231→      workspaceId,
   232→      conversationId: conversationRecord.id as string,
   233→      messageCount: messages.length,
   234→      seedCount: seeds.length,
   235→      durationMs: elapsedMs(startedAt),
   236→    });
   237→
   238→    return jsonResponse(payload, 200);
   239→  } catch (error) {
   240→    if (error instanceof HttpError) {
   241→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
   242→        workspaceId,
   243→        statusCode: error.status,
   244→      });
   245→      return jsonError(error.message, error.status);
   246→    }
   247→
   248→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
   249→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
   250→    return jsonError(errorText, 500);
   251→  }
   252→}
