   254→async function resolveWorkspaceBootstrapConversation(
   255→  deps: ServerDependencies,
   256→  workspaceRecord: RecordId<"workspace", string>,
   257→): Promise<RecordId<"conversation", string>> {
   258→  const [onboardingRows] = await deps.surreal
   259→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
   260→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
   261→      {
   262→        workspace: workspaceRecord,
   263→      },
   264→    )
   265→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
   266→
   267→  if (onboardingRows.length > 0) {
   268→    return onboardingRows[0].id;
   269→  }
   270→
   271→  const [latestRows] = await deps.surreal
   272→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
   273→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
   274→      {
   275→        workspace: workspaceRecord,
   276→      },
   277→    )
   278→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
   279→
   280→  if (latestRows.length > 0) {
   281→    return latestRows[0].id;
   282→  }
   283→
   284→  const now = new Date();
   285→  const conversationRecord = new RecordId("conversation", randomUUID());
   286→  await deps.surreal.create(conversationRecord).content({
   287→    createdAt: now,
   288→    updatedAt: now,
   289→    workspace: workspaceRecord,
   290→    source: "onboarding",
   291→  });
   292→  return conversationRecord;
   293→}
