   295→async function loadWorkspaceSeeds(
   296→  deps: ServerDependencies,
   297→  workspaceRecord: RecordId<"workspace", string>,
   298→  limit: number,
   299→): Promise<OnboardingSeedItem[]> {
   300→  const [edgeRows] = await deps.surreal
   301→    .query<[ProvenanceEdgeRow[]]>(
   302→      [
   303→        "SELECT id, `in`, out, confidence, extracted_at",
   304→        "FROM extraction_relation",
   305→        "WHERE `in` IN array::concat(",
   306→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
   307→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
   308→        ")",
   309→        "ORDER BY extracted_at DESC",
   310→        "LIMIT $limit;",
   311→      ].join(" "),
   312→      {
   313→        workspace: workspaceRecord,
   314→        limit,
   315→      },
   316→    )
   317→    .collect<[ProvenanceEdgeRow[]]>();
   318→
   319→  const items: OnboardingSeedItem[] = [];
   320→
   321→  for (const edge of edgeRows) {
   322→    const entityText = await readEntityText(deps.surreal, edge.out);
   323→    if (!entityText) {
   324→      continue;
   325→    }
   326→
   327→    const sourceTable = edge.in.table.name;
   328→    const entityTable = edge.out.table.name;
   329→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
   330→    const sourceLabel = await readSourceLabel(deps, edge.in);
   331→
   332→    items.push({
   333→      id: edge.out.id as string,
   334→      kind: entityTable as EntityKind,
   335→      text: entityText,
   336→      confidence: edge.confidence,
   337→      sourceKind,
   338→      sourceId: edge.in.id as string,
   339→      ...(sourceLabel ? { sourceLabel } : {}),
   340→    });
   341→  }
   342→
   343→  return items;
   344→}
   345→
   346→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
   347→  const sourceTable = sourceRecord.table.name;
   348→  if (sourceTable === "message") {
   349→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
   350→    if (!row) {
   351→      return undefined;
   352→    }
   353→    return row.text.slice(0, 140);
   354→  }
   355→
   356→  const chunk = await deps.surreal.select<{
   357→    section_heading?: string;
   358→    document: RecordId<"document", string>;
   359→  }>(sourceRecord);
   360→
   361→  if (!chunk) {
   362→    return undefined;
   363→  }
   364→
   365→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
   366→  if (!document) {
   367→    return chunk.section_heading;
   368→  }
   369→
   370→  if (chunk.section_heading) {
   371→    return `${document.name} · ${chunk.section_heading}`;
   372→  }
   373→
   374→  return document.name;
   375→}
