   377→async function handleWorkspaceSidebar(deps: ServerDependencies, workspaceId: string): Promise<Response> {
   378→  const startedAt = performance.now();
   379→  logInfo("workspace.sidebar.started", "Workspace sidebar request started", { workspaceId });
   380→
   381→  try {
   382→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
   383→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
   384→
   385→    logInfo("workspace.sidebar.completed", "Workspace sidebar request completed", {
   386→      workspaceId,
   387→      groupCount: sidebar.groups.length,
   388→      unlinkedCount: sidebar.unlinked.length,
   389→      durationMs: elapsedMs(startedAt),
   390→    });
   391→
   392→    return jsonResponse(sidebar, 200);
   393→  } catch (error) {
   394→    if (error instanceof HttpError) {
   395→      logWarn("workspace.sidebar.http_error", "Workspace sidebar failed with client-facing error", {
   396→        workspaceId,
   397→        statusCode: error.status,
   398→      });
   399→      return jsonError(error.message, error.status);
   400→    }
   401→
   402→    logError("workspace.sidebar.failed", "Workspace sidebar request failed", error, { workspaceId });
   403→    const errorText = error instanceof Error ? error.message : "workspace sidebar failed";
   404→    return jsonError(errorText, 500);
   405→  }
   406→}
   407→
   408→async function handleWorkspaceConversation(
   409→  deps: ServerDependencies,
   410→  workspaceId: string,
   411→  conversationId: string,
   412→): Promise<Response> {
   413→  const startedAt = performance.now();
   414→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
   415→    workspaceId,
   416→    conversationId,
   417→  });
   418→
   419→  try {
   420→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
   421→    const conversationRecord = new RecordId("conversation", conversationId);
   422→    const conversation = await deps.surreal.select<{
   423→      id: RecordId<"conversation", string>;
   424→      workspace: RecordId<"workspace", string>;
   425→      discusses?: RecordId;
   426→    }>(conversationRecord);
   427→
   428→    if (!conversation) {
   429→      throw new HttpError(404, `conversation not found: ${conversationId}`);
   430→    }
   431→
   432→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
   433→      throw new HttpError(400, "conversation does not belong to workspace");
   434→    }
   435→
   436→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
   437→
   438→    const messages = rawMessages.map((row) => ({
   439→      id: row.id,
   440→      role: row.role,
   441→      text: row.text,
   442→      createdAt: toIsoString(row.createdAt),
   443→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
   444→      ...(row.inherited ? { inherited: true } : {}),
   445→    } satisfies WorkspaceBootstrapMessage));
   446→
   447→    let discussEntity: DiscussEntitySummary | undefined;
   448→    if (conversation.discusses) {
   449→      const entityRecord = conversation.discusses as GraphEntityRecord;
   450→      const name = await readEntityName(deps.surreal, entityRecord);
   451→      if (name) {
   452→        const entityRow = await deps.surreal.select<Record<string, unknown>>(entityRecord);
   453→        discussEntity = {
   454→          id: `${entityRecord.table.name}:${entityRecord.id as string}`,
   455→          kind: entityRecord.table.name as EntityKind,
   456→          name,
   457→          ...(entityRow && typeof entityRow.status === "string" ? { status: entityRow.status } : {}),
   458→        };
   459→      }
   460→    }
   461→
   462→    const payload: WorkspaceConversationResponse = {
   463→      conversationId,
   464→      messages,
   465→      ...(discussEntity ? { discussEntity } : {}),
   466→    };
   467→
   468→    logInfo("workspace.conversation.completed", "Workspace conversation request completed", {
   469→      workspaceId,
   470→      conversationId,
   471→      messageCount: messages.length,
   472→      durationMs: elapsedMs(startedAt),
   473→    });
   474→
   475→    return jsonResponse(payload, 200);
   476→  } catch (error) {
   477→    if (error instanceof HttpError) {
   478→      logWarn("workspace.conversation.http_error", "Workspace conversation failed with client-facing error", {
   479→        workspaceId,
   480→        conversationId,
   481→        statusCode: error.status,
   482→      });
   483→      return jsonError(error.message, error.status);
   484→    }
   485→
   486→    logError("workspace.conversation.failed", "Workspace conversation request failed", error, {
   487→      workspaceId,
   488→      conversationId,
   489→    });
   490→    const errorText = error instanceof Error ? error.message : "workspace conversation failed";
   491→    return jsonError(errorText, 500);
   492→  }
   493→}
